1	package middleware
2	
3	import (
4		"fmt"
5		"net/http"
6		"strings"
7		"time"
8	
9		"wlpr-portal/internal/services"
10		"wlpr-portal/pkg/jwt"
11	
12		"github.com/labstack/echo/v4"
13	)
14	
15	type AuthMiddleware struct {
16		authService   *services.AuthService
17		configService *services.ConfigService
18	}
19	
20	func NewAuthMiddleware(authService *services.AuthService, configService *services.ConfigService) *AuthMiddleware {
21		return &AuthMiddleware{
22			authService:   authService,
23			configService: configService,
24		}
25	}
26	
27	// RequireAuth validates the JWT, checks session validity (idle/max), and injects claims into context.
28	func (m *AuthMiddleware) RequireAuth() echo.MiddlewareFunc {
29		return func(next echo.HandlerFunc) echo.HandlerFunc {
30			return func(c echo.Context) error {
31				authHeader := c.Request().Header.Get("Authorization")
32				if authHeader == "" {
33					return echo.NewHTTPError(http.StatusUnauthorized, "missing authorization header")
34				}
35	
36				parts := strings.SplitN(authHeader, " ", 2)
37				if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
38					return echo.NewHTTPError(http.StatusUnauthorized, "invalid authorization format")
39				}
40	
41				claims, err := jwt.ValidateToken(parts[1])
42				if err != nil {
43					return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired token")
44				}
45	
46				// Validate session (idle timeout / max lifetime)
47				session, err := m.authService.ValidateSession(c.Request().Context(), claims.SessionID)
48				if err != nil || session == nil {
49					return echo.NewHTTPError(http.StatusUnauthorized, "session expired")
50				}
51	
52				// Store claims in context for downstream handlers
53				c.Set("claims", claims)
54				c.Set("user_id", claims.UserID)
55				c.Set("username", claims.Username)
56				c.Set("roles", claims.Roles)
57				c.Set("role_ids", claims.RoleIDs)
58				c.Set("permissions", claims.Permissions)
59				c.Set("session_id", claims.SessionID)
60	
61				return next(c)
62			}
63		}
64	}
65	
66	// RequireRole checks that the authenticated user has at least one of the specified roles.
67	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
68	func (m *AuthMiddleware) RequireRole(roles ...string) echo.MiddlewareFunc {
69		return func(next echo.HandlerFunc) echo.HandlerFunc {
70			return func(c echo.Context) error {
71				userRoles, ok := c.Get("roles").([]string)
72				if !ok || len(userRoles) == 0 {
73					return echo.NewHTTPError(http.StatusNotFound)
74				}
75	
76				for _, required := range roles {
77					for _, userRole := range userRoles {
78						if required == userRole {
79							return next(c)
80						}
81					}
82				}
83	
84				// Feature invisibility: user without the role should not know the endpoint exists
85				return echo.NewHTTPError(http.StatusNotFound)
86			}
87		}
88	}
89	
90	// RequirePermission checks that the authenticated user has at least one of the specified permissions.
91	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
92	func (m *AuthMiddleware) RequirePermission(perms ...string) echo.MiddlewareFunc {
93		return func(next echo.HandlerFunc) echo.HandlerFunc {
94			return func(c echo.Context) error {
95				userPerms, ok := c.Get("permissions").([]string)
96				if !ok || len(userPerms) == 0 {
97					return echo.NewHTTPError(http.StatusNotFound)
98				}
99	
100				for _, required := range perms {
101					for _, userPerm := range userPerms {
102						if required == userPerm {
103							return next(c)
104						}
105					}
106				}
107	
108				return echo.NewHTTPError(http.StatusNotFound)
109			}
110		}
111	}
112	
113	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
114	// Clients below the minimum supported version enter a 14-day (configurable) read-only grace
115	// period. During grace, GET/HEAD/OPTIONS requests are allowed but writes are blocked.
116	// After the grace period expires, all requests are blocked.
117	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
118		return func(next echo.HandlerFunc) echo.HandlerFunc {
119			return func(c echo.Context) error {
120				clientVersion := c.Request().Header.Get("X-App-Version")
121				if clientVersion == "" {
122					return next(c) // Allow requests without version header (browser clients)
123				}
124	
125				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
126				if minVersion == "" {
127					return next(c)
128				}
129	
130				if compareVersions(clientVersion, minVersion) < 0 {
131					// Determine grace period: how long the min_version has been in effect
132					graceDays := 14
133					if val, ok := m.configService.GetConfig("app.read_only_grace_days"); ok {
134						var d int
135						if _, err := fmt.Sscanf(val, "%d", &d); err == nil && d > 0 {
136							graceDays = d
137						}
138					}
139	
140					// Get the timestamp when the min_supported_version was last updated
141					// (approximated by the config's updated_at). If not available, treat
142					// as if just updated (full grace period).
143					minVersionSetAt := m.configService.GetConfigUpdatedAt("app.min_supported_version")
144	
145					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
146					withinGrace := time.Now().Before(graceDeadline)
147	
148					c.Response().Header().Set("X-App-Deprecated", "true")
149					c.Response().Header().Set("X-Min-Version", minVersion)
150	
151					if !withinGrace {
152						// Grace period expired: hard block ALL requests
153						return echo.NewHTTPError(http.StatusUpgradeRequired,
154							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
155					}
156	
157					// Within grace period: allow read-only access
158					c.Set("read_only", true)
159					daysLeft := int(time.Until(graceDeadline).Hours() / 24)
160					c.Response().Header().Set("X-Grace-Days-Remaining", fmt.Sprintf("%d", daysLeft))
161	
162					method := c.Request().Method
163					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
164						return echo.NewHTTPError(http.StatusUpgradeRequired,
165							fmt.Sprintf("client version unsupported; read-only access for %d more days. Upgrade to %s or later.",
166								daysLeft, minVersion))
167					}
168				}
169	
170				return next(c)
171			}
172		}
173	}
174	
175	// compareVersions compares semver strings. Returns -1, 0, or 1.
176	func compareVersions(a, b string) int {
177		partsA := strings.Split(a, ".")
178		partsB := strings.Split(b, ".")
179	
180		maxLen := len(partsA)
181		if len(partsB) > maxLen {
182			maxLen = len(partsB)
183		}
184	
185		for i := 0; i < maxLen; i++ {
186			var va, vb int
187			if i < len(partsA) {
188				for _, ch := range partsA[i] {
189					if ch >= '0' && ch <= '9' {
190						va = va*10 + int(ch-'0')
191					}
192				}
193			}
194			if i < len(partsB) {
195				for _, ch := range partsB[i] {
196					if ch >= '0' && ch <= '9' {
197						vb = vb*10 + int(ch-'0')
198					}
199				}
200			}
201			if va < vb {
202				return -1
203			}
204			if va > vb {
205				return 1
206			}
207		}
208		return 0
209	}
