20	func TestCompareVersions_LessThan(t *testing.T) {
21		if compareVersions("0.9.0", "1.0.0") >= 0 {
22			t.Error("0.9.0 < 1.0.0")
23		}
24		if compareVersions("1.0.0", "1.0.1") >= 0 {
25			t.Error("1.0.0 < 1.0.1")
26		}
27		if compareVersions("1.2.3", "2.0.0") >= 0 {
28			t.Error("1.2.3 < 2.0.0")
29		}
30	}
