76	func TestAppVersionCheck_NoHeader_Allowed(t *testing.T) {
77		e := echo.New()
78		e.Use(versionCheckMiddleware("2.0.0", time.Now(), 14))
79		e.GET("/test", func(c echo.Context) error {
80			return c.String(http.StatusOK, "ok")
81		})
82	
83		req := httptest.NewRequest(http.MethodGet, "/test", nil)
84		rec := httptest.NewRecorder()
85		e.ServeHTTP(rec, req)
86	
87		if rec.Code != http.StatusOK {
88			t.Fatalf("no version header should pass, got %d", rec.Code)
89		}
90	}
