1	package services
2	
3	import (
4		"context"
5		"fmt"
6		"hash/fnv"
7		"log"
8		"sync"
9		"time"
10	
11		"wlpr-portal/internal/models"
12		"wlpr-portal/internal/repository"
13	)
14	
15	// ConfigService provides in-memory cached access to configs and feature flags.
16	type ConfigService struct {
17		configRepo *repository.ConfigRepository
18	
19		mu      sync.RWMutex
20		configs map[string]models.Config
21		flags   map[string]models.FeatureFlag
22	}
23	
24	func NewConfigService(configRepo *repository.ConfigRepository) *ConfigService {
25		return &ConfigService{
26			configRepo: configRepo,
27			configs:    make(map[string]models.Config),
28			flags:      make(map[string]models.FeatureFlag),
29		}
30	}
31	
32	// NewConfigServiceForTest creates a ConfigService with pre-loaded configs for testing
33	// without requiring a database connection.
34	func NewConfigServiceForTest(configs map[string]models.Config) *ConfigService {
35		return &ConfigService{
36			configs: configs,
37			flags:   make(map[string]models.FeatureFlag),
38		}
39	}
40	
41	// LoadAll fetches all configs and flags from DB into the in-memory cache.
42	func (s *ConfigService) LoadAll(ctx context.Context) error {
43		configs, err := s.configRepo.GetAllConfigs(ctx)
44		if err != nil {
45			return err
46		}
47		flags, err := s.configRepo.GetAllFeatureFlags(ctx)
48		if err != nil {
49			return err
50		}
51	
52		s.mu.Lock()
53		defer s.mu.Unlock()
54	
55		s.configs = make(map[string]models.Config, len(configs))
56		for _, c := range configs {
57			s.configs[c.Key] = c
58		}
59	
60		s.flags = make(map[string]models.FeatureFlag, len(flags))
61		for _, f := range flags {
62			s.flags[f.Key] = f
63		}
64	
65		return nil
66	}
67	
68	// StartBackgroundSync periodically refreshes the in-memory cache from DB.
69	func (s *ConfigService) StartBackgroundSync(ctx context.Context, interval time.Duration) {
70		go func() {
71			ticker := time.NewTicker(interval)
72			defer ticker.Stop()
73			for {
74				select {
75				case <-ctx.Done():
76					return
77				case <-ticker.C:
78					if err := s.LoadAll(ctx); err != nil {
79						log.Printf("[config-sync] failed to reload configs: %v", err)
80					}
81				}
82			}
83		}()
84	}
85	
86	// GetConfig returns a cached config value. Falls through to DB on cache miss.
87	func (s *ConfigService) GetConfig(key string) (string, bool) {
88		s.mu.RLock()
89		defer s.mu.RUnlock()
90		c, ok := s.configs[key]
91		if !ok {
92			return "", false
93		}
94		return c.Value, true
95	}
96	
97	// GetConfigUpdatedAt returns the updated_at timestamp for a config key.
98	// Returns time.Now() if the key is not found (conservative: full grace period).
99	func (s *ConfigService) GetConfigUpdatedAt(key string) time.Time {
100		s.mu.RLock()
101		defer s.mu.RUnlock()
102		c, ok := s.configs[key]
103		if !ok {
104			return time.Now()
105		}
106		return c.UpdatedAt
107	}
