109	// GetAllConfigs returns all cached configs.
110	func (s *ConfigService) GetAllConfigs() []models.Config {
111		s.mu.RLock()
112		defer s.mu.RUnlock()
113		result := make([]models.Config, 0, len(s.configs))
114		for _, c := range s.configs {
115			result = append(result, c)
116		}
117		return result
