126			result = append(result, f)
127		}
128		return result
129	}
130	
131	// IsFlagEnabled checks if a feature flag is enabled for a given user.
132	// userID is used for deterministic percentage bucketing.
133	// userRoleIDs is used for role_based rollout strategy.
134	func (s *ConfigService) IsFlagEnabled(key string, userID int, userRoleIDs []int) bool {
135		s.mu.RLock()
136		defer s.mu.RUnlock()
137	
138		f, ok := s.flags[key]
139		if !ok || !f.Enabled {
140			return false
141		}
142	
143		switch f.RolloutStrategy {
144		case "all":
145			return true
146		case "disabled":
147			return false
148		case "role_based":
149			if len(userRoleIDs) == 0 {
150				return false
151			}
152			for _, allowed := range f.AllowedRoles {
153				for _, userRole := range userRoleIDs {
154					if allowed == userRole {
155						return true
156					}
157				}
158			}
159			return false
160		case "percentage":
161			if f.RolloutPercentage <= 0 {
162				return false
163			}
164			if f.RolloutPercentage >= 100 {
165				return true
166			}
167			if userID == 0 {
168				return false
169			}
170			// Deterministic bucketing: hash(userID, flagKey) % 100 < rolloutPercentage
171			h := fnv.New32a()
172			_, _ = h.Write([]byte(fmt.Sprintf("%d:%s", userID, key)))
173			bucket := int(h.Sum32() % 100)
174			return bucket < f.RolloutPercentage
175		default:
176			return false
177		}
178	}
