136	// POST /api/auth/register  (public)
137	// The first user to register is auto-assigned system_admin (bootstrap).
138	// All subsequent users may only self-select non-privileged roles.
139	// Privileged roles (system_admin) are assigned by an admin via /api/admin/users/assign-role.
140	func (h *AuthHandler) Register(c echo.Context) error {
141		var req models.RegisterRequest
142		if err := c.Bind(&req); err != nil {
143			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
144		}
145	
146		if strings.TrimSpace(req.Username) == "" || strings.TrimSpace(req.Email) == "" ||
147			strings.TrimSpace(req.Password) == "" || strings.TrimSpace(req.DisplayName) == "" {
148			return echo.NewHTTPError(http.StatusBadRequest, "username, email, password, and display_name are required")
149		}
150		if len(req.Password) < 8 {
151			return echo.NewHTTPError(http.StatusBadRequest, "password must be at least 8 characters")
152		}
153		// Validate role field early (before any DB calls).
154		// Role must be present and must be recognized (either self-reg or admin role).
155		// The first user's role is overridden to system_admin regardless.
156		if strings.TrimSpace(req.Role) == "" {
157			return echo.NewHTTPError(http.StatusBadRequest, "role is required")
158		}
159		if !models.AllRoles()[req.Role] {
160			return echo.NewHTTPError(http.StatusBadRequest,
161				"invalid role; choose one of: learner, procurement_specialist, approver, finance_analyst, content_moderator")
162		}
163	
164		ctx := c.Request().Context()
165	
166		// Check if this is the very first user (bootstrap: auto-assign system_admin)
167		userCount, err := h.userRepo.CountUsers(ctx)
168		if err != nil {
169			log.Printf("[auth] count users error: %v", err)
170			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
171		}
172		isFirstUser := userCount == 0
173	
174		var assignedRole string
175		if isFirstUser {
176			// First user bootstrap: ignore the requested role and assign system_admin
177			assignedRole = "system_admin"
178		} else {
179			// Subsequent users: must use a self-registration role (no system_admin)
180			if !models.ValidRoles()[req.Role] {
181				return echo.NewHTTPError(http.StatusBadRequest,
182					"invalid role; choose one of: learner, procurement_specialist, approver, finance_analyst, content_moderator")
183			}
184			assignedRole = req.Role
185		}
186	
187		existing, err := h.userRepo.FindByUsername(ctx, req.Username)
188		if err != nil {
189			log.Printf("[auth] find user error: %v", err)
190			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
191		}
192		if existing != nil {
193			return echo.NewHTTPError(http.StatusConflict, "username already taken")
194		}
195	
196		hashedPassword, err := crypto.HashPassword(req.Password)
197		if err != nil {
198			log.Printf("[auth] hash error: %v", err)
199			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
200		}
201	
202		user, err := h.userRepo.CreateUser(ctx, req.Username, req.Email, hashedPassword,
203			req.DisplayName, req.JobFamily, req.Department, req.CostCenter)
204		if err != nil {
205			if strings.Contains(err.Error(), "duplicate key") {
206				if strings.Contains(err.Error(), "email") {
207					return echo.NewHTTPError(http.StatusConflict, "email already registered")
208				}
209				return echo.NewHTTPError(http.StatusConflict, "username already taken")
210			}
211			log.Printf("[auth] create user error: %v", err)
212			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
213		}
214	
215		if err := h.userRepo.AssignRole(ctx, user.ID, assignedRole, nil); err != nil {
216			log.Printf("[auth] assign role error user=%d role=%s: %v", user.ID, assignedRole, err)
217			return echo.NewHTTPError(http.StatusInternalServerError, "registration succeeded but role assignment failed; contact an administrator")
218		}
219	
220		uwr, err := h.userRepo.GetUserWithRoles(ctx, user.ID)
221		if err != nil {
222			uwr = &models.UserWithRoles{User: *user}
223		}
224	
225		msg := fmt.Sprintf("Registration successful. You have been assigned the %s role.",
226			strings.ReplaceAll(assignedRole, "_", " "))
227		if isFirstUser {
228			msg = "Welcome! As the first user, you have been assigned the system admin role."
229		}
230	
231		return c.JSON(http.StatusCreated, models.RegisterResponse{
232			Message: msg,
233			User:    uwr,
234		})
235	}
