240		if err != nil {
241			log.Printf("[admin] list users error: %v", err)
242			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve users")
243		}
244		return c.JSON(http.StatusOK, users)
245	}
246	
247	// POST /api/admin/users/assign-role  (admin only)
248	func (h *AuthHandler) AssignRole(c echo.Context) error {
249		var req models.AssignRoleRequest
250		if err := c.Bind(&req); err != nil {
251			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
252		}
253		if req.UserID == 0 || req.Role == "" {
254			return echo.NewHTTPError(http.StatusBadRequest, "user_id and role are required")
255		}
256	
257		if !models.AllRoles()[req.Role] {
258			return echo.NewHTTPError(http.StatusBadRequest, "invalid role name")
259		}
260	
261		adminID := c.Get("user_id").(int)
262		if err := h.userRepo.AssignRole(c.Request().Context(), req.UserID, req.Role, &adminID); err != nil {
263			log.Printf("[admin] assign role error user=%d role=%s: %v", req.UserID, req.Role, err)
264			return echo.NewHTTPError(http.StatusInternalServerError, "failed to assign role")
265		}
266	
267		return c.JSON(http.StatusOK, map[string]string{
268			"message": fmt.Sprintf("role '%s' assigned to user %d", req.Role, req.UserID),
269		})
270	}
