23	func (h *SearchHandler) Search(c echo.Context) error {
24		req := models.SearchRequest{
25			Query:      c.QueryParam("q"),
26			DateFrom:   c.QueryParam("date_from"),
27			DateTo:     c.QueryParam("date_to"),
28			Difficulty: c.QueryParam("difficulty"),
