91	func parseIntList(s string) []int {
92		if s == "" {
93			return nil
94		}
95		var result []int
96		for _, part := range splitComma(s) {
97			if id, err := strconv.Atoi(part); err == nil {
98				result = append(result, id)
99			}
100		}
101		return result
102	}
103	
104	func splitComma(s string) []string {
105		var parts []string
106		current := ""
107		for _, ch := range s {
108			if ch == ',' {
109				if current != "" {
110					parts = append(parts, current)
111				}
112				current = ""
113			} else {
114				current += string(ch)
115			}
116		}
117		if current != "" {
118			parts = append(parts, current)
119		}
120		return parts
121	}
