2	import client from '../api/client';
3	
4	const STORAGE_KEY = 'wlpr_auth';
5	
6	function loadPersistedAuth() {
7	  try {
8	    const raw = localStorage.getItem(STORAGE_KEY);
9	    if (!raw) return null;
10	    const data = JSON.parse(raw);
11	    // Check if token is still present (basic check; server validates fully)
12	    if (data.token) return data;
13	    return null;
14	  } catch {
15	    return null;
16	  }
17	}
18	
19	function persistAuth(state) {
20	  if (state.token) {
21	    localStorage.setItem(
22	      STORAGE_KEY,
23	      JSON.stringify({
24	        token: state.token,
25	        user: state.user,
26	      })
27	    );
28	  } else {
29	    localStorage.removeItem(STORAGE_KEY);
30	  }
31	}
32	
33	const persisted = loadPersistedAuth();
34	
35	export const useAuthStore = create((set, get) => ({
36	  // Auth state
37	  token: persisted?.token || null,
38	  user: persisted?.user || null,
39	  isAuthenticated: !!persisted?.token,
40	  mfaPending: false,
41	  mfaSessionId: null,
42	
43	  // UI state
44	  loading: false,
45	  error: null,
46	  accessDenied: false,
47	  versionBlocked: false,
48	  deprecationWarning: null,
49	
50	  // Login step 1: credentials
51	  login: async (username, password) => {
