1	import axios from 'axios';
2	import { useAuthStore } from '../store/authStore';
3	
4	// Runtime config from config.js (injected via Docker volume or served statically)
5	const runtimeConfig = window.__WLPR_CONFIG__ || {};
6	const API_BASE_URL = runtimeConfig.API_BASE_URL || '/api';
7	const APP_VERSION = runtimeConfig.APP_VERSION || '1.0.0';
8	
9	const client = axios.create({
10	  baseURL: API_BASE_URL,
11	  timeout: 30000,
12	  headers: {
13	    'Content-Type': 'application/json',
14	    'X-App-Version': APP_VERSION,
15	  },
16	});
17	
18	// Request interceptor: attach JWT token
19	client.interceptors.request.use(
20	  (config) => {
21	    const token = useAuthStore.getState().token;
22	    if (token) {
23	      config.headers.Authorization = `Bearer ${token}`;
24	    }
25	    return config;
26	  },
27	  (error) => Promise.reject(error)
28	);
29	
30	// Response interceptor: handle auth errors, version warnings, retries
31	client.interceptors.response.use(
32	  (response) => {
33	    // Check for app deprecation warning
34	    if (response.headers['x-app-deprecated'] === 'true') {
35	      const minVersion = response.headers['x-min-version'] || 'unknown';
36	      console.warn(
37	        `[WLPR] Client version deprecated. Minimum: ${minVersion}. Write operations may be blocked.`
38	      );
39	      useAuthStore.getState().setDeprecationWarning(minVersion);
40	    }
41	    return response;
42	  },
43	  async (error) => {
44	    const originalRequest = error.config;
45	
46	    // 401 Unauthorized -> force logout
47	    if (error.response?.status === 401) {
48	      useAuthStore.getState().logout();
49	      window.location.href = '/login';
50	      return Promise.reject(error);
51	    }
52	
53	    // 403 Forbidden -> set access denied state
54	    if (error.response?.status === 403) {
55	      useAuthStore.getState().setAccessDenied(true);
56	      return Promise.reject(error);
57	    }
58	
59	    // 426 Upgrade Required -> version blocked
60	    if (error.response?.status === 426) {
61	      useAuthStore.getState().setVersionBlocked(true);
62	      return Promise.reject(error);
63	    }
64	
65	    // 5xx -> retry once
66	    if (
67	      error.response?.status >= 500 &&
68	      !originalRequest._retried
69	    ) {
70	      originalRequest._retried = true;
71	      return client(originalRequest);
72	    }
73	
74	    return Promise.reject(error);
75	  }
76	);
