1	package handlers
2	
3	import (
4		"encoding/csv"
5		"fmt"
6		"log"
7		"net/http"
8		"strconv"
9	
10		"wlpr-portal/internal/models"
11		"wlpr-portal/internal/services"
12	
13		"github.com/labstack/echo/v4"
14	)
15	
16	type LearningHandler struct {
17		learningService *services.LearningService
18	}
19	
20	func NewLearningHandler(learningService *services.LearningService) *LearningHandler {
21		return &LearningHandler{learningService: learningService}
22	}
23	
24	// GET /api/learning/paths
25	func (h *LearningHandler) GetPaths(c echo.Context) error {
26		paths, err := h.learningService.GetAllPaths(c.Request().Context())
27		if err != nil {
28			log.Printf("[learning] get paths error: %v", err)
29			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve learning paths")
30		}
31		return c.JSON(http.StatusOK, paths)
32	}
33	
34	// GET /api/learning/paths/:id
35	func (h *LearningHandler) GetPath(c echo.Context) error {
36		id, err := strconv.Atoi(c.Param("id"))
37		if err != nil {
38			return echo.NewHTTPError(http.StatusBadRequest, "invalid path ID")
39		}
40	
41		path, err := h.learningService.GetPathDetail(c.Request().Context(), id)
42		if err != nil || path == nil {
43			return echo.NewHTTPError(http.StatusNotFound, "learning path not found")
44		}
45		return c.JSON(http.StatusOK, path)
46	}
47	
48	// POST /api/learning/enroll
49	func (h *LearningHandler) Enroll(c echo.Context) error {
50		userID := c.Get("user_id").(int)
51		var body struct {
52			PathID int `json:"path_id"`
53		}
54		if err := c.Bind(&body); err != nil || body.PathID == 0 {
55			return echo.NewHTTPError(http.StatusBadRequest, "path_id is required")
56		}
57	
58		enrollment, err := h.learningService.Enroll(c.Request().Context(), userID, body.PathID)
59		if err != nil {
60			log.Printf("[learning] enroll error: %v", err)
61			return echo.NewHTTPError(http.StatusBadRequest, "enrollment failed")
62		}
63		return c.JSON(http.StatusCreated, enrollment)
64	}
65	
66	// DELETE /api/learning/enroll/:path_id
67	func (h *LearningHandler) DropEnrollment(c echo.Context) error {
68		userID := c.Get("user_id").(int)
69		pathID, err := strconv.Atoi(c.Param("path_id"))
70		if err != nil {
71			return echo.NewHTTPError(http.StatusBadRequest, "invalid path ID")
72		}
73	
74		if err := h.learningService.DropEnrollment(c.Request().Context(), userID, pathID); err != nil {
75			log.Printf("[learning] drop enrollment error: %v", err)
76			return echo.NewHTTPError(http.StatusInternalServerError, "failed to drop enrollment")
77		}
78		return c.JSON(http.StatusOK, map[string]string{"message": "enrollment dropped"})
79	}
80	
81	// GET /api/learning/enrollments
82	func (h *LearningHandler) GetEnrollments(c echo.Context) error {
83		userID := c.Get("user_id").(int)
84		enrollments, err := h.learningService.GetEnrollments(c.Request().Context(), userID)
85		if err != nil {
86			log.Printf("[learning] get enrollments error: %v", err)
87			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve enrollments")
88		}
89		return c.JSON(http.StatusOK, enrollments)
90	}
91	
92	// GET /api/learning/enrollments/:path_id
93	func (h *LearningHandler) GetEnrollmentDetail(c echo.Context) error {
94		userID := c.Get("user_id").(int)
95		pathID, err := strconv.Atoi(c.Param("path_id"))
96		if err != nil {
97			return echo.NewHTTPError(http.StatusBadRequest, "invalid path ID")
98		}
99	
100		detail, err := h.learningService.GetEnrollmentDetail(c.Request().Context(), userID, pathID)
101		if err != nil {
102			log.Printf("[learning] get enrollment detail error: %v", err)
103			return echo.NewHTTPError(http.StatusNotFound, "enrollment not found")
104		}
105		return c.JSON(http.StatusOK, detail)
106	}
107	
108	// PUT /api/learning/progress
109	func (h *LearningHandler) UpdateProgress(c echo.Context) error {
110		userID := c.Get("user_id").(int)
111		var req models.UpdateProgressRequest
112		if err := c.Bind(&req); err != nil {
113			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
114		}
115		if req.ResourceID == 0 {
116			return echo.NewHTTPError(http.StatusBadRequest, "resource_id is required")
117		}
118		if req.Status == "" {
119			req.Status = "in_progress"
120		}
121	
122		progress, err := h.learningService.UpdateProgress(c.Request().Context(), userID, req)
123		if err != nil {
124			log.Printf("[learning] update progress error: %v", err)
125			return echo.NewHTTPError(http.StatusInternalServerError, "failed to update progress")
126		}
127		return c.JSON(http.StatusOK, progress)
128	}
129	
130	// GET /api/learning/progress?path_id=1
131	func (h *LearningHandler) GetProgress(c echo.Context) error {
132		userID := c.Get("user_id").(int)
133		var pathID *int
134		if pid := c.QueryParam("path_id"); pid != "" {
135			if id, err := strconv.Atoi(pid); err == nil {
136				pathID = &id
137			}
138		}
139	
140		progress, err := h.learningService.GetProgress(c.Request().Context(), userID, pathID)
141		if err != nil {
142			log.Printf("[learning] get progress error: %v", err)
143			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve progress")
144		}
145		return c.JSON(http.StatusOK, progress)
146	}
147	
148	// GET /api/learning/export
149	// Streams a CSV download of the authenticated user's learning records.
150	func (h *LearningHandler) ExportCSV(c echo.Context) error {
151		userID := c.Get("user_id").(int)
152	
153		records, err := h.learningService.GetLearningRecords(c.Request().Context(), userID)
154		if err != nil {
155			log.Printf("[learning] export CSV error: %v", err)
156			return echo.NewHTTPError(http.StatusInternalServerError, "failed to export learning records")
157		}
158	
159		c.Response().Header().Set("Content-Type", "text/csv")
160		c.Response().Header().Set("Content-Disposition", "attachment; filename=learning_records.csv")
161		c.Response().WriteHeader(http.StatusOK)
162	
163		writer := csv.NewWriter(c.Response().Writer)
164	
165		// Write header
166		_ = writer.Write([]string{
167			"Username", "Resource Title", "Learning Path", "Status",
168			"Progress %", "Time Spent (mins)", "Started At", "Completed At",
169		})
170	
171		// Stream rows
172		for _, r := range records {
173			_ = writer.Write([]string{
174				r.Username,
175				r.ResourceTitle,
176				r.PathTitle,
177				r.Status,
178				fmt.Sprintf("%d", r.ProgressPct),
179				fmt.Sprintf("%d", r.TimeSpentMin),
180				r.StartedAt,
181				r.CompletedAt,
182			})
183		}
184	
185		writer.Flush()
186		return nil
187	}
188	
189	// GET /api/learning/recommendations?limit=20
190	func (h *LearningHandler) GetRecommendations(c echo.Context) error {
191		userID := c.Get("user_id").(int)
192		limit := 20
193		if l, err := strconv.Atoi(c.QueryParam("limit")); err == nil && l > 0 {
194			limit = l
195		}
196	
197		recs, err := h.learningService.GetRecommendations(c.Request().Context(), userID, limit)
198		if err != nil {
199			log.Printf("[learning] get recommendations error: %v", err)
200			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve recommendations")
201		}
202		return c.JSON(http.StatusOK, recs)
203	}
204	
