20	// isAdmin checks whether the current user has system_admin or content_moderator role.
21	func isAdmin(c echo.Context) bool {
22		roles, ok := c.Get("roles").([]string)
23		if !ok {
24			return false
25		}
26		for _, r := range roles {
27			if r == "system_admin" || r == "content_moderator" {
28				return true
29			}
30		}
31		return false
