34	// decryptDisputeMetadata decrypts evidence_metadata_enc and populates the EvidenceMetadata field.
35	// Only called for admin-role users; non-admin users never see the decrypted metadata.
36	func decryptDisputeMetadata(d *models.Dispute) {
37		if len(d.EvidenceMetadataEnc) > 0 {
38			plaintext, err := crypto.DecryptString(d.EvidenceMetadataEnc)
39			if err != nil {
40				log.Printf("[procurement] evidence metadata decryption error dispute=%d: %v", d.ID, err)
41				return
42			}
43			d.EvidenceMetadata = &plaintext
44		}
45	}
