261		c.Response().WriteHeader(http.StatusOK)
262	
263		writer := csv.NewWriter(c.Response().Writer)
264		_ = writer.Write([]string{
265			"Entry ID", "Type", "Reference Type", "Reference ID",
266			"Vendor ID", "Vendor Name", "Amount", "Currency",
267			"Department", "Cost Center", "Description", "Posted At",
268		})
269	
270		for _, e := range entries {
271			dept, cc, desc := "", "", ""
272			if e.Department != nil {
273				dept = *e.Department
274			}
275			if e.CostCenter != nil {
276				cc = *e.CostCenter
277			}
278			if e.Description != nil {
279				desc = *e.Description
280			}
281			_ = writer.Write([]string{
282				fmt.Sprintf("%d", e.ID), e.EntryType, e.ReferenceType,
283				fmt.Sprintf("%d", e.ReferenceID), fmt.Sprintf("%d", e.VendorID),
284				e.VendorName, fmt.Sprintf("%.2f", e.Amount), e.Currency,
285				dept, cc, desc, e.PostedAt.Format("2006-01-02 15:04:05"),
286			})
287		}
288	
289		writer.Flush()
290		return nil
291	}
