167	// TransitionDispute validates and executes dispute state transitions.
168	// The DB trigger trg_dispute_state_machine also enforces this, providing defense-in-depth.
169	//
170	// Valid transitions:
171	//
172	//	created -> evidence_uploaded
173	//	evidence_uploaded -> under_review
174	//	under_review -> arbitration
175	//	arbitration -> resolved_hidden | resolved_disclaimer | resolved_restored | rejected
176	func (s *ReconciliationService) TransitionDispute(ctx context.Context, req models.DisputeTransitionRequest, userID int) error {
177		dispute, err := s.procRepo.GetDisputeByID(ctx, req.DisputeID)
178		if err != nil || dispute == nil {
179			return fmt.Errorf("dispute not found")
180		}
181	
182		currentStatus := dispute.Status
183		var newStatus string
184		updates := make(map[string]interface{})
185	
186		switch req.Action {
187		case "upload_evidence":
188			if currentStatus != "created" {
189				return fmt.Errorf("invalid transition: cannot upload evidence from status %s (must be 'created')", currentStatus)
190			}
191			if len(req.EvidenceURLs) == 0 {
192				return fmt.Errorf("at least one evidence URL is required")
193			}
194			newStatus = "evidence_uploaded"
195			updates["evidence_urls"] = req.EvidenceURLs
196	
197			// Encrypt evidence metadata at rest if provided
198			if req.EvidenceMetadata != "" {
199				encMeta, err := crypto.EncryptString(req.EvidenceMetadata)
200				if err != nil {
201					log.Printf("[reconciliation] evidence metadata encryption error: %v", err)
202					return fmt.Errorf("failed to encrypt evidence metadata")
203				}
204				updates["evidence_metadata_enc"] = encMeta
205			}
