func init() {
	// Shared JWT secret for this test file.
	if err := jwt.InitJWTSecretFromValue("test-secret-key-at-least-32-characters-for-security"); err != nil {
		panic("failed to init JWT secret in security tests: " + err.Error())
	}
}

// mockAuthService is a minimal stub for AuthService used in tests so we can
// call the real RequireAuth middleware without a database.
type mockAuthService struct {
	sessions map[string]*models.Session
}

func (m *mockAuthService) ValidateSession(sessionID string) (*models.Session, error) {
	if s, ok := m.sessions[sessionID]; ok {
		return s, nil
	}
	return nil, nil
}

// buildTestAuthMiddleware constructs a real AuthMiddleware with an in-memory
// ConfigService and a mock AuthService — no database required.
func buildTestAuthMiddleware(configs map[string]models.Config) (*AuthMiddleware, *mockAuthService) {
	configSvc := services.NewConfigServiceForTest(configs)
	mock := &mockAuthService{
		sessions: map[string]*models.Session{
			"test-session-id": {
				ID:     "test-session-id",
				UserID: 1,
				Status: "active",
			},
		},
	}

	// AuthMiddleware takes an *services.AuthService which has a private ValidateSession.
	// To avoid coupling to the concrete type, we wrap it through a real AuthService
	// backed by a nil repo. Since we inject session state directly, we use the
	// existing NewConfigServiceForTest approach and build the middleware manually
	// using the same constructor signature.
	//
	// For this test we create a thin AuthService wrapper that uses the mockAuthService.
	// We build the middleware directly so we can inject the mock validator.
	mw := &AuthMiddleware{
		authService:   nil, // replaced by authValidator below
		configService: configSvc,
		authValidator: mock.ValidateSession,
	}
	return mw, mock
}

// makeToken generates a signed test JWT.
func makeToken(t *testing.T, userID int, sessionID string, roles []string, perms []string) string {
	t.Helper()
	roleIDs := make([]int, len(roles))
	roleMap := map[string]int{
		"system_admin": 1, "content_moderator": 2, "learner": 3,
		"procurement_specialist": 4, "approver": 5, "finance_analyst": 6,
	}
	for i, r := range roles {
		if id, ok := roleMap[r]; ok {
			roleIDs[i] = id
		}
	}
	tok, err := jwt.GenerateToken(userID, "testuser", sessionID, roles, roleIDs, perms)
	if err != nil {
		t.Fatalf("makeToken: %v", err)
	}
	return tok
}

