27	// RequireAuth validates the JWT, checks session validity (idle/max), and injects claims into context.
28	func (m *AuthMiddleware) RequireAuth() echo.MiddlewareFunc {
29		return func(next echo.HandlerFunc) echo.HandlerFunc {
30			return func(c echo.Context) error {
31				authHeader := c.Request().Header.Get("Authorization")
32				if authHeader == "" {
33					return echo.NewHTTPError(http.StatusUnauthorized, "missing authorization header")
34				}
35	
36				parts := strings.SplitN(authHeader, " ", 2)
37				if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
38					return echo.NewHTTPError(http.StatusUnauthorized, "invalid authorization format")
39				}
40	
41				claims, err := jwt.ValidateToken(parts[1])
42				if err != nil {
43					return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired token")
44				}
45	
46				// Validate session (idle timeout / max lifetime)
47				session, err := m.authService.ValidateSession(c.Request().Context(), claims.SessionID)
48				if err != nil || session == nil {
49					return echo.NewHTTPError(http.StatusUnauthorized, "session expired")
50				}
51	
52				// Store claims in context for downstream handlers
53				c.Set("claims", claims)
54				c.Set("user_id", claims.UserID)
55				c.Set("username", claims.Username)
56				c.Set("roles", claims.Roles)
57				c.Set("role_ids", claims.RoleIDs)
58				c.Set("permissions", claims.Permissions)
59				c.Set("session_id", claims.SessionID)
60	
61				return next(c)
62			}
63		}
64	}
65	
66	// RequireRole checks that the authenticated user has at least one of the specified roles.
67	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
68	func (m *AuthMiddleware) RequireRole(roles ...string) echo.MiddlewareFunc {
69		return func(next echo.HandlerFunc) echo.HandlerFunc {
70			return func(c echo.Context) error {
71				userRoles, ok := c.Get("roles").([]string)
72				if !ok || len(userRoles) == 0 {
73					return echo.NewHTTPError(http.StatusNotFound)
74				}
75	
76				for _, required := range roles {
77					for _, userRole := range userRoles {
78						if required == userRole {
79							return next(c)
80						}
81					}
82				}
83	
84				// Feature invisibility: user without the role should not know the endpoint exists
85				return echo.NewHTTPError(http.StatusNotFound)
86			}
87		}
88	}
89	
90	// RequirePermission checks that the authenticated user has at least one of the specified permissions.
91	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
92	func (m *AuthMiddleware) RequirePermission(perms ...string) echo.MiddlewareFunc {
93		return func(next echo.HandlerFunc) echo.HandlerFunc {
94			return func(c echo.Context) error {
95				userPerms, ok := c.Get("permissions").([]string)
96				if !ok || len(userPerms) == 0 {
97					return echo.NewHTTPError(http.StatusNotFound)
98				}
99	
100				for _, required := range perms {
101					for _, userPerm := range userPerms {
102						if required == userPerm {
103							return next(c)
104						}
105					}
106				}
107	
108				return echo.NewHTTPError(http.StatusNotFound)
109			}
110		}
111	}
112	
113	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
114	// Clients below the minimum supported version enter a 14-day (configurable) read-only grace
115	// period. During grace, GET/HEAD/OPTIONS requests are allowed but writes are blocked.
116	// After the grace period expires, all requests are blocked.
117	// If no version header is provided, the client is treated as version "0.0.0" (oldest possible)
118	// so that the compatibility policy is still enforced.
119	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
120		return func(next echo.HandlerFunc) echo.HandlerFunc {
121			return func(c echo.Context) error {
122				clientVersion := c.Request().Header.Get("X-App-Version")
123	
124				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
125				if minVersion == "" {
126					// No minimum version configured — skip enforcement
127					return next(c)
128				}
129	
130				if clientVersion == "" {
131					// Missing version header: treat as oldest client ("0.0.0")
132					// so the compatibility policy still applies.
133					clientVersion = "0.0.0"
134				}
135	
136				if compareVersions(clientVersion, minVersion) < 0 {
137					// Determine grace period: how long the min_version has been in effect
138					graceDays := 14
139					if val, ok := m.configService.GetConfig("app.read_only_grace_days"); ok {
140						var d int
141						if _, err := fmt.Sscanf(val, "%d", &d); err == nil && d > 0 {
142							graceDays = d
143						}
144					}
145	
146					// Get the timestamp when the min_supported_version was last updated
147					// (approximated by the config's updated_at). If not available, treat
148					// as if just updated (full grace period).
149					minVersionSetAt := m.configService.GetConfigUpdatedAt("app.min_supported_version")
150	
151					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
152					withinGrace := time.Now().Before(graceDeadline)
153	
154					c.Response().Header().Set("X-App-Deprecated", "true")
155					c.Response().Header().Set("X-Min-Version", minVersion)
156	
157					if !withinGrace {
158						// Grace period expired: hard block ALL requests
159						return echo.NewHTTPError(http.StatusUpgradeRequired,
160							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
161					}
162	
163					// Within grace period: allow read-only access
164					c.Set("read_only", true)
165					daysLeft := int(time.Until(graceDeadline).Hours() / 24)
166					c.Response().Header().Set("X-Grace-Days-Remaining", fmt.Sprintf("%d", daysLeft))
167	
168					method := c.Request().Method
169					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
170						return echo.NewHTTPError(http.StatusUpgradeRequired,
171							fmt.Sprintf("client version unsupported; read-only access for %d more days. Upgrade to %s or later.",
172								daysLeft, minVersion))
173					}
174				}
175	
176				return next(c)
177			}
178		}
179	}
180	
181	// compareVersions compares semver strings. Returns -1, 0, or 1.
182	func compareVersions(a, b string) int {
183		partsA := strings.Split(a, ".")
184		partsB := strings.Split(b, ".")
185	
186		maxLen := len(partsA)
187		if len(partsB) > maxLen {
188			maxLen = len(partsB)
189		}
190	
191		for i := 0; i < maxLen; i++ {
192			var va, vb int
193			if i < len(partsA) {
194				for _, ch := range partsA[i] {
195					if ch >= '0' && ch <= '9' {
196						va = va*10 + int(ch-'0')
197					}
198				}
199			}
200			if i < len(partsB) {
201				for _, ch := range partsB[i] {
202					if ch >= '0' && ch <= '9' {
203						vb = vb*10 + int(ch-'0')
204					}
205				}
206			}
207			if va < vb {
208				return -1
209			}
210			if va > vb {
211				return 1
212			}
213		}
214		return 0
215	}
