1	package services
2	
3	import (
4		"context"
5		"crypto/sha256"
6		"encoding/hex"
7		"fmt"
8		"time"
9	
10		"wlpr-portal/internal/models"
11		"wlpr-portal/internal/repository"
12		"wlpr-portal/pkg/crypto"
13		"wlpr-portal/pkg/jwt"
14	
15		"github.com/google/uuid"
16	)
17	
18	type AuthService struct {
19		userRepo   *repository.UserRepository
20		configRepo *repository.ConfigRepository
21	}
22	
23	func NewAuthService(userRepo *repository.UserRepository, configRepo *repository.ConfigRepository) *AuthService {
24		return &AuthService{
25			userRepo:   userRepo,
26			configRepo: configRepo,
27		}
28	}
29	
30	// Login performs credential validation and returns either a token or an MFA challenge.
31	func (s *AuthService) Login(ctx context.Context, req models.LoginRequest, ipAddress, userAgent string) (*models.LoginResponse, error) {
32		user, err := s.userRepo.FindByUsername(ctx, req.Username)
33		if err != nil {
34			return nil, fmt.Errorf("database error: %w", err)
35		}
36		if user == nil {
37			return nil, fmt.Errorf("invalid credentials")
38		}
39	
40		if !user.IsActive {
41			return nil, fmt.Errorf("account is disabled")
42		}
43	
44		if user.LockedUntil != nil && time.Now().Before(*user.LockedUntil) {
45			return nil, fmt.Errorf("account is locked until %s", user.LockedUntil.Format(time.RFC3339))
46		}
47	
48		if !crypto.CheckPassword(req.Password, user.PasswordHash) {
49			_ = s.userRepo.IncrementFailedLogin(ctx, user.ID)
50			return nil, fmt.Errorf("invalid credentials")
51		}
52	
53		_ = s.userRepo.ResetFailedLogin(ctx, user.ID)
54	
55		// Get session timeout configs
56		idleTimeout := 900  // 15 min default
57		maxLifetime := 28800 // 8 hours default
58		if cfg, err := s.configRepo.GetConfigByKey(ctx, "session.idle_timeout_seconds"); err == nil && cfg != nil {
59			fmt.Sscanf(cfg.Value, "%d", &idleTimeout)
60		}
61		if cfg, err := s.configRepo.GetConfigByKey(ctx, "session.max_lifetime_seconds"); err == nil && cfg != nil {
62			fmt.Sscanf(cfg.Value, "%d", &maxLifetime)
63		}
64	
65		now := time.Now()
66		sessionID := uuid.New().String()
67	
68		session := &models.Session{
69			ID:           sessionID,
70			UserID:       user.ID,
71			TokenHash:    "", // will be set after token generation
72			Status:       "active",
73			IPAddress:    ipAddress,
74			UserAgent:    userAgent,
75			CreatedAt:    now,
76			LastActiveAt: now,
77			ExpiresAt:    now.Add(time.Duration(maxLifetime) * time.Second),
78			IdleTimeoutS: idleTimeout,
79			MaxLifetimeS: maxLifetime,
80		}
81	
82		if user.MFAEnabled {
83			// Create a pending session; token is not issued yet
84			session.TokenHash = "pending_mfa"
85			if err := s.userRepo.CreateSession(ctx, session); err != nil {
86				return nil, fmt.Errorf("failed to create session: %w", err)
87			}
88			return &models.LoginResponse{
89				RequiresMFA: true,
90				SessionID:   sessionID,
91			}, nil
92		}
93	
94		// No MFA: issue token directly
95		return s.issueToken(ctx, user, session)
96	}
97	
98	// VerifyMFA validates TOTP code and issues a token for a pending MFA session.
99	func (s *AuthService) VerifyMFA(ctx context.Context, req models.MFAVerifyRequest) (*models.LoginResponse, error) {
100		session, err := s.userRepo.GetSession(ctx, req.SessionID)
101		if err != nil || session == nil {
102			return nil, fmt.Errorf("invalid session")
103		}
104		if session.TokenHash != "pending_mfa" {
105			return nil, fmt.Errorf("session is not pending MFA")
106		}
107	
108		user, err := s.userRepo.FindByID(ctx, session.UserID)
109		if err != nil || user == nil {
110			return nil, fmt.Errorf("user not found")
111		}
112	
113		if !user.MFAEnabled || user.MFASecretEnc == nil {
114			return nil, fmt.Errorf("MFA not configured for this user")
115		}
116	
117		secret, err := crypto.DecryptString(user.MFASecretEnc)
118		if err != nil {
119			return nil, fmt.Errorf("failed to decrypt MFA secret")
120		}
121	
122		if !ValidateTOTP(secret, req.Code) {
123			return nil, fmt.Errorf("invalid MFA code")
124		}
125	
126		return s.issueToken(ctx, user, session)
127	}
128	
129	func (s *AuthService) issueToken(ctx context.Context, user *models.User, session *models.Session) (*models.LoginResponse, error) {
130		roles, err := s.userRepo.GetUserRoles(ctx, user.ID)
131		if err != nil {
132			return nil, fmt.Errorf("failed to fetch roles: %w", err)
133		}
134	
135		perms, err := s.userRepo.GetUserPermissions(ctx, user.ID)
136		if err != nil {
137			return nil, fmt.Errorf("failed to fetch permissions: %w", err)
138		}
139	
140		roleNames := make([]string, len(roles))
141		roleIDs := make([]int, len(roles))
142		for i, r := range roles {
143			roleNames[i] = r.Name
144			roleIDs[i] = r.ID
145		}
146	
147		token, err := jwt.GenerateToken(user.ID, user.Username, session.ID, roleNames, roleIDs, perms)
148		if err != nil {
149			return nil, fmt.Errorf("failed to generate token: %w", err)
150		}
151	
152		// Store token hash in session
153		h := sha256.Sum256([]byte(token))
154		session.TokenHash = hex.EncodeToString(h[:])
155		if err := s.userRepo.CreateSession(ctx, session); err != nil {
156			// If session already exists (MFA flow), update token hash
157			_ = s.userRepo.TouchSession(ctx, session.ID)
158		}
159	
160		_ = s.userRepo.LogAudit(ctx, user.ID, "login", "auth", "user", user.ID, session.IPAddress)
161	
162		return &models.LoginResponse{
163			Token:       token,
164			RequiresMFA: false,
165			User: &models.UserWithRoles{
166				User:        *user,
167				Roles:       roles,
168				Permissions: perms,
169			},
170		}, nil
171	}
172	
173	// Logout revokes the session.
174	func (s *AuthService) Logout(ctx context.Context, sessionID string, userID int, ip string) error {
175		_ = s.userRepo.RevokeSession(ctx, sessionID)
176		_ = s.userRepo.LogAudit(ctx, userID, "logout", "auth", "session", 0, ip)
177		return nil
178	}
179	
180	// ValidateSession checks that the session is still active, not idle, not expired.
181	func (s *AuthService) ValidateSession(ctx context.Context, sessionID string) (*models.Session, error) {
182		session, err := s.userRepo.GetSession(ctx, sessionID)
183		if err != nil {
184			return nil, err
185		}
186		if session == nil {
187			return nil, fmt.Errorf("session not found")
188		}
189		if !repository.IsSessionValid(session) {
190			_ = s.userRepo.RevokeSession(ctx, sessionID)
191			return nil, fmt.Errorf("session expired")
192		}
193		_ = s.userRepo.TouchSession(ctx, sessionID)
194		return session, nil
195	}
