27	// RequireAuth validates the JWT, checks session validity (idle/max), and injects claims into context.
28	func (m *AuthMiddleware) RequireAuth() echo.MiddlewareFunc {
29		return func(next echo.HandlerFunc) echo.HandlerFunc {
30			return func(c echo.Context) error {
31				authHeader := c.Request().Header.Get("Authorization")
32				if authHeader == "" {
33					return echo.NewHTTPError(http.StatusUnauthorized, "missing authorization header")
34				}
35	
36				parts := strings.SplitN(authHeader, " ", 2)
37				if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
38					return echo.NewHTTPError(http.StatusUnauthorized, "invalid authorization format")
39				}
40	
41				claims, err := jwt.ValidateToken(parts[1])
42				if err != nil {
43					return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired token")
44				}
45	
46				// Validate session (idle timeout / max lifetime).
47				// authService may be nil in unit tests that exercise only JWT + RBAC
48				// logic without a live database — in that case the JWT signature is
49				// trusted and session validation is skipped.
50				if m.authService != nil {
51					session, err := m.authService.ValidateSession(c.Request().Context(), claims.SessionID)
52					if err != nil || session == nil {
53						return echo.NewHTTPError(http.StatusUnauthorized, "session expired")
54					}
55				}
56	
57				// Store claims in context for downstream handlers
58				c.Set("claims", claims)
59				c.Set("user_id", claims.UserID)
60				c.Set("username", claims.Username)
61				c.Set("roles", claims.Roles)
62				c.Set("role_ids", claims.RoleIDs)
63				c.Set("permissions", claims.Permissions)
64				c.Set("session_id", claims.SessionID)
65	
66				return next(c)
67			}
68		}
69	}
