71	// RequireRole checks that the authenticated user has at least one of the specified roles.
72	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
73	func (m *AuthMiddleware) RequireRole(roles ...string) echo.MiddlewareFunc {
74		return func(next echo.HandlerFunc) echo.HandlerFunc {
75			return func(c echo.Context) error {
76				userRoles, ok := c.Get("roles").([]string)
77				if !ok || len(userRoles) == 0 {
78					return echo.NewHTTPError(http.StatusNotFound)
79				}
80	
81				for _, required := range roles {
82					for _, userRole := range userRoles {
83						if required == userRole {
84							return next(c)
85						}
86					}
87				}
88	
89				// Feature invisibility: user without the role should not know the endpoint exists
90				return echo.NewHTTPError(http.StatusNotFound)
91			}
92		}
93	}
94	
95	// RequirePermission checks that the authenticated user has at least one of the specified permissions.
96	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
97	func (m *AuthMiddleware) RequirePermission(perms ...string) echo.MiddlewareFunc {
98		return func(next echo.HandlerFunc) echo.HandlerFunc {
99			return func(c echo.Context) error {
100				userPerms, ok := c.Get("permissions").([]string)
101				if !ok || len(userPerms) == 0 {
102					return echo.NewHTTPError(http.StatusNotFound)
103				}
104	
105				for _, required := range perms {
106					for _, userPerm := range userPerms {
107						if required == userPerm {
108							return next(c)
109						}
110					}
111				}
112	
113				return echo.NewHTTPError(http.StatusNotFound)
114			}
115		}
116	}
