118	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
119	// Clients below the minimum supported version enter a 14-day (configurable) read-only grace
120	// period. During grace, GET/HEAD/OPTIONS requests are allowed but writes are blocked.
121	// After the grace period expires, all requests are blocked.
122	// If no version header is provided, the client is treated as version "0.0.0" (oldest possible)
123	// so that the compatibility policy is still enforced.
124	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
125		return func(next echo.HandlerFunc) echo.HandlerFunc {
126			return func(c echo.Context) error {
127				clientVersion := c.Request().Header.Get("X-App-Version")
128	
129				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
130				if minVersion == "" {
131					// No minimum version configured — skip enforcement
132					return next(c)
133				}
134	
135				if clientVersion == "" {
136					// Missing version header: treat as oldest client ("0.0.0")
137					// so the compatibility policy still applies.
138					clientVersion = "0.0.0"
139				}
140	
141				if compareVersions(clientVersion, minVersion) < 0 {
142					// Determine grace period: how long the min_version has been in effect
143					graceDays := 14
144					if val, ok := m.configService.GetConfig("app.read_only_grace_days"); ok {
145						var d int
146						if _, err := fmt.Sscanf(val, "%d", &d); err == nil && d > 0 {
147							graceDays = d
148						}
149					}
150	
151					// Get the timestamp when the min_supported_version was last updated
152					// (approximated by the config's updated_at). If not available, treat
153					// as if just updated (full grace period).
154					minVersionSetAt := m.configService.GetConfigUpdatedAt("app.min_supported_version")
155	
156					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
157					withinGrace := time.Now().Before(graceDeadline)
158	
159					c.Response().Header().Set("X-App-Deprecated", "true")
160					c.Response().Header().Set("X-Min-Version", minVersion)
161	
162					if !withinGrace {
163						// Grace period expired: hard block ALL requests
164						return echo.NewHTTPError(http.StatusUpgradeRequired,
165							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
166					}
167	
168					// Within grace period: allow read-only access
169					c.Set("read_only", true)
170					daysLeft := int(time.Until(graceDeadline).Hours() / 24)
171					c.Response().Header().Set("X-Grace-Days-Remaining", fmt.Sprintf("%d", daysLeft))
172	
173					method := c.Request().Method
174					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
175						return echo.NewHTTPError(http.StatusUpgradeRequired,
176							fmt.Sprintf("client version unsupported; read-only access for %d more days. Upgrade to %s or later.",
177								daysLeft, minVersion))
178					}
179				}
180	
181				return next(c)
182			}
183		}
184	}
185	
186	// compareVersions compares semver strings. Returns -1, 0, or 1.
187	func compareVersions(a, b string) int {
188		partsA := strings.Split(a, ".")
189		partsB := strings.Split(b, ".")
190	
191		maxLen := len(partsA)
192		if len(partsB) > maxLen {
193			maxLen = len(partsB)
194		}
195	
196		for i := 0; i < maxLen; i++ {
197			var va, vb int
198			if i < len(partsA) {
199				for _, ch := range partsA[i] {
200					if ch >= '0' && ch <= '9' {
201						va = va*10 + int(ch-'0')
202					}
203				}
204			}
205			if i < len(partsB) {
206				for _, ch := range partsB[i] {
207					if ch >= '0' && ch <= '9' {
208						vb = vb*10 + int(ch-'0')
209					}
210				}
211			}
212			if va < vb {
213				return -1
214			}
215			if va > vb {
216				return 1
217			}
218		}
219		return 0
220	}
