53	// TestIntegration_SchedulerRepo_RunLifecycle tests the full run lifecycle:
54	// start -> success, start -> failure, start -> compensation.
55	func TestIntegration_SchedulerRepo_RunLifecycle(t *testing.T) {
56		db := getTestDB(t)
57		defer db.Close()
58		ctx := context.Background()
59	
60		repo := NewSchedulerRepository(db)
61	
62		// Get a job to work with
63		jobs, err := repo.GetEnabledJobs(ctx)
64		if err != nil || len(jobs) == 0 {
65			t.Fatalf("need at least one enabled job: %v", err)
66		}
67		job := jobs[0]
68	
69		t.Run("SuccessfulRun", func(t *testing.T) {
70			runID, err := repo.RecordRunStart(ctx, job.ID, 0)
71			if err != nil {
72				t.Fatalf("RecordRunStart failed: %v", err)
73			}
74	
75			err = repo.RecordRunSuccess(ctx, runID, job.ID)
76			if err != nil {
77				t.Fatalf("RecordRunSuccess failed: %v", err)
78			}
79	
80			// Verify run record
81			var status string
82			err = db.QueryRow(ctx, "SELECT status FROM scheduled_job_runs WHERE id = $1", runID).Scan(&status)
83			if err != nil {
84				t.Fatalf("query run status: %v", err)
85			}
86			if status != "success" {
87				t.Errorf("expected run status 'success', got %q", status)
88			}
89	
90			// Verify job was updated
91			var lastStatus *string
92			err = db.QueryRow(ctx, "SELECT last_status FROM scheduled_jobs WHERE id = $1", job.ID).Scan(&lastStatus)
93			if err != nil || lastStatus == nil || *lastStatus != "success" {
94				t.Errorf("expected job last_status 'success', got %v", lastStatus)
95			}
96	
97			// Cleanup
98			db.Exec(ctx, "DELETE FROM scheduled_job_runs WHERE id = $1", runID)
99		})
100	
101		t.Run("FailedRun_IncrementsRetry", func(t *testing.T) {
102			// Reset retry count
103			repo.ResetRetryCount(ctx, job.ID)
104	
105			runID, err := repo.RecordRunStart(ctx, job.ID, 0)
106			if err != nil {
107				t.Fatalf("RecordRunStart failed: %v", err)
108			}
109	
110			err = repo.RecordRunFailure(ctx, runID, job.ID, "test error: connection timeout")
111			if err != nil {
112				t.Fatalf("RecordRunFailure failed: %v", err)
113			}
114	
115			// Verify run record
116			var status string
117			var errMsg *string
118			err = db.QueryRow(ctx, "SELECT status, error_message FROM scheduled_job_runs WHERE id = $1", runID).Scan(&status, &errMsg)
119			if err != nil {
120				t.Fatalf("query run: %v", err)
121			}
122			if status != "failed" {
123				t.Errorf("expected run status 'failed', got %q", status)
124			}
125			if errMsg == nil || *errMsg != "test error: connection timeout" {
126				t.Errorf("expected error message 'test error: connection timeout', got %v", errMsg)
127			}
128	
129			// Verify retry count incremented
130			var retryCount int
131			db.QueryRow(ctx, "SELECT retry_count FROM scheduled_jobs WHERE id = $1", job.ID).Scan(&retryCount)
132			if retryCount != 1 {
133				t.Errorf("expected retry_count=1, got %d", retryCount)
134			}
135	
136			// Cleanup
137			db.Exec(ctx, "DELETE FROM scheduled_job_runs WHERE id = $1", runID)
138			repo.ResetRetryCount(ctx, job.ID)
139		})
140	
141		t.Run("CompensatedRun_ResetsRetry", func(t *testing.T) {
142			runID, err := repo.RecordRunStart(ctx, job.ID, 3)
143			if err != nil {
144				t.Fatalf("RecordRunStart failed: %v", err)
145			}
