41	// --- AppVersionCheck grace-period middleware behavior tests ---
42	// These use inline middleware stubs that replicate the exact logic from
43	// AppVersionCheck so the tests run without a DB or real config service.
44	
45	// versionCheckMiddleware replicates AppVersionCheck logic with injected params.
46	func versionCheckMiddleware(minVersion string, minVersionSetAt time.Time, graceDays int) echo.MiddlewareFunc {
47		return func(next echo.HandlerFunc) echo.HandlerFunc {
48			return func(c echo.Context) error {
49				if minVersion == "" {
50					return next(c)
51				}
52				v := c.Request().Header.Get("X-App-Version")
53				if v == "" {
54					// Missing version header: treat as oldest client ("0.0.0")
55					v = "0.0.0"
56				}
57				if compareVersions(v, minVersion) < 0 {
58					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
59					withinGrace := time.Now().Before(graceDeadline)
60	
61					c.Response().Header().Set("X-App-Deprecated", "true")
62					c.Response().Header().Set("X-Min-Version", minVersion)
63	
64					if !withinGrace {
65						return echo.NewHTTPError(http.StatusUpgradeRequired,
66							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
67					}
68	
69					c.Set("read_only", true)
70					method := c.Request().Method
71					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
72						return echo.NewHTTPError(http.StatusUpgradeRequired, "read-only during grace period")
73					}
74				}
75				return next(c)
76			}
77		}
78	}
