80	func TestAppVersionCheck_NoHeader_WithMinVersion_TreatedAsOldest(t *testing.T) {
81		// When min version is configured and header is missing, client is treated as "0.0.0".
82		// Since the min was just set (now), grace period is fully active, so GET is allowed
83		// but the client is flagged as deprecated.
84		e := echo.New()
85		e.Use(versionCheckMiddleware("2.0.0", time.Now(), 14))
86		e.GET("/test", func(c echo.Context) error {
87			return c.String(http.StatusOK, "ok")
88		})
89	
