		{ResourceID: 2, Score: 90},
		{ResourceID: 3, Score: 80},
	}

	hashMap := map[int]string{
		1: "hash_a",
		2: "hash_b",
		3: "hash_c",
	}

	result := w.deduplicateByContentHash(recs, hashMap)

	if len(result) != 3 {
		t.Fatalf("all unique hashes should be kept, got %d", len(result))
	}
}

