		[]string{"finance_analyst"},
		[]string{"finance.reconciliation.view"},
	)

	tests := []struct {
		name       string
		token      string
		method     string
		path       string
		wantStatus int
	}{
		{"learner_blocked_settlements_GET", learnerToken, "GET", "/api/procurement/settlements", http.StatusNotFound},
