23	// simulateApprove simulates the approval logic:
24	// 1. Check review item is pending
25	// 2. Activate the entity
26	// 3. Mark review item as approved
27	func simulateApprove(queue []reviewQueueEntry, entities map[string][]entityRecord, reviewItemID int) (string, error) {
28		for i, item := range queue {
29			if item.ID == reviewItemID {
30				if item.Status != "pending" {
31					return "", nil
32				}
33	
34				// Activate entity
35				for j, ent := range entities[item.EntityType] {
36					if ent.ID == item.EntityID {
37						entities[item.EntityType][j].Status = "active"
38					}
39				}
40	
41				// Mark approved
42				queue[i].Status = "approved"
43				return "approved", nil
44			}
45		}
46		return "", nil
47	}
48	
49	// simulateReject simulates the rejection logic
50	func simulateReject(queue []reviewQueueEntry, entities map[string][]entityRecord, reviewItemID int) (string, error) {
51		for i, item := range queue {
52			if item.ID == reviewItemID {
53				if item.Status != "pending" {
54					return "", nil
55				}
56	
57				// Reject entity
58				for j, ent := range entities[item.EntityType] {
59					if ent.ID == item.EntityID {
60						entities[item.EntityType][j].Status = "rejected"
61					}
62				}
63	
64				// Mark rejected
65				queue[i].Status = "rejected"
66				return "rejected", nil
67			}
68		}
69		return "", nil
70	}
