7	// The synonym conflict detection is enforced by a PostgreSQL trigger (check_synonym_conflict),
8	// so the definitive test is an integration test against a real DB. However, we can validate
9	// the backend's conflict detection logic rules here as unit tests.
10	
11	// synonymConflictExists checks whether adding a new active synonym with the given term
12	// and canonical_tag_id would conflict with existing active synonyms.
13	// This mirrors the logic in the PostgreSQL trigger check_synonym_conflict().
14	func synonymConflictExists(existingSynonyms []testSynonym, newTerm string, newCanonicalID int) bool {
15		for _, existing := range existingSynonyms {
16			if existing.Status != "active" {
17				continue
18			}
19			if existing.Term == newTerm && existing.CanonicalTagID != newCanonicalID {
20				return true
21			}
22		}
23		return false
24	}
25	
26	type testSynonym struct {
27		ID             int
28		Term           string
29		CanonicalTagID int
30		Status         string
31	}
32	
33	func TestSynonymConflict_DuplicateActiveBlocksDifferentCanonical(t *testing.T) {
34		// Pre-existing: "ML" -> canonical tag 3 (Data Science), active
35		existing := []testSynonym{
36			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "active"},
37		}
38	
39		// Attempt: "ML" -> canonical tag 7 (Go) — MUST conflict
40		if !synonymConflictExists(existing, "ML", 7) {
41			t.Error("expected conflict: term 'ML' already maps to canonical 3, cannot also map to 7")
42		}
43	}
44	
