func TestIntegration_DisputeStateMachine_BlocksInvalidTransition(t *testing.T) {
	db := getTestDB(t)
	defer db.Close()
	ctx := context.Background()

	// Create a temporary test vendor and review so we have valid FKs
	var vendorID, reviewID, disputeID int

	err := db.QueryRow(ctx, `
