32	else { Log-Fail "Services not healthy"; docker compose logs; docker compose down -v; exit 1 }
33	
34	Log-Info "Phase 2: Verifying endpoints..."
35	try { $h = Invoke-RestMethod -Uri "http://localhost:${API_PORT}/api/health"; if ($h.status -eq "ok") { Log-Pass "Backend health OK" } } catch { Log-Fail "Backend health failed" }
36	try { $f = Invoke-WebRequest -Uri "http://localhost:${UI_PORT}/"; if ($f.Content -match "WLPR Portal") { Log-Pass "Frontend OK" } } catch { Log-Fail "Frontend failed" }
37	try { $c = Invoke-WebRequest -Uri "http://localhost:${UI_PORT}/config.js"; if ($c.Content -match "__WLPR_CONFIG__") { Log-Pass "config.js OK" } } catch { Log-Fail "config.js failed" }
38	
