1	#!/usr/bin/env pwsh
2	$ErrorActionPreference = "Continue"
3	$scriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
4	Set-Location $scriptDir
5	
6	$failed = 0
7	function Log-Pass($msg) { Write-Host "[PASS] $msg" -ForegroundColor Green }
8	function Log-Fail($msg) { Write-Host "[FAIL] $msg" -ForegroundColor Red; $script:failed = 1 }
9	function Log-Info($msg) { Write-Host "[INFO] $msg" -ForegroundColor Yellow }
10	
11	# Port configuration (must match docker-compose.yml)
12	$API_PORT = 8081
13	$UI_PORT = 3001
14	
15	Log-Info "Phase 1: Building and starting Docker containers..."
16	docker compose down -v --remove-orphans 2>$null
17	$buildResult = docker compose build --no-cache --progress=plain 2>&1
18	if ($LASTEXITCODE -eq 0) { Log-Pass "Docker build succeeded" }
19	else { Log-Fail "Docker build failed"; Write-Host $buildResult; exit 1 }
20	
21	# Start containers (may exit non-zero due to health check race; we poll manually)
22	docker compose up -d 2>$null
23	Log-Info "Waiting for services to become healthy..."
24	$healthy = $false
25	for ($i = 1; $i -le 30; $i++) {
26	    try {
27	        $resp = Invoke-RestMethod -Uri "http://localhost:${API_PORT}/api/health" -TimeoutSec 3 -ErrorAction SilentlyContinue
28	        if ($resp.status -eq "ok") { $healthy = $true; break }
29	    } catch {}
30	    Start-Sleep -Seconds 2
31	}
32	if ($healthy) { Log-Pass "All services are healthy" }
33	else { Log-Fail "Services not healthy"; docker compose logs; docker compose down -v; exit 1 }
34	
35	Log-Info "Phase 2: Verifying endpoints..."
36	try { $h = Invoke-RestMethod -Uri "http://localhost:${API_PORT}/api/health"; if ($h.status -eq "ok") { Log-Pass "Backend health OK" } } catch { Log-Fail "Backend health failed" }
37	try { $f = Invoke-WebRequest -Uri "http://localhost:${UI_PORT}/"; if ($f.Content -match "WLPR Portal") { Log-Pass "Frontend OK" } } catch { Log-Fail "Frontend failed" }
38	try { $c = Invoke-WebRequest -Uri "http://localhost:${UI_PORT}/config.js"; if ($c.Content -match "__WLPR_CONFIG__") { Log-Pass "config.js OK" } } catch { Log-Fail "config.js failed" }
39	
40	Log-Info "Phase 3: Registration and API smoke tests..."
41	try {
42	    $reg = Invoke-RestMethod -Method Post -Uri "http://localhost:${API_PORT}/api/auth/register" -ContentType "application/json" -Body '{"username":"testadmin","email":"ta@test.local","password":"TestAdmin@2024!","display_name":"Test Admin","role":"system_admin"}'
43	    if ($reg.message) { Log-Pass "First user registered (auto-admin)" } else { Log-Fail "Registration failed" }
44	} catch { Log-Fail "Registration error: $_" }
45	
46	try {
47	    $login = Invoke-RestMethod -Method Post -Uri "http://localhost:${API_PORT}/api/auth/login" -ContentType "application/json" -Body '{"username":"testadmin","password":"TestAdmin@2024!"}'
48	    if ($login.token) {
49	        Log-Pass "Admin login succeeded"
50	        $headers = @{ "Authorization" = "Bearer $($login.token)" }
51	        $me = Invoke-RestMethod -Uri "http://localhost:${API_PORT}/api/auth/me" -Headers $headers
52	        if ($me.user_id) { Log-Pass "GET /api/auth/me OK" }
53	
54	        # Register second user with learner role
55	        $reg2 = Invoke-RestMethod -Method Post -Uri "http://localhost:${API_PORT}/api/auth/register" -ContentType "application/json" -Body '{"username":"testlearner","email":"tl@test.local","password":"Learner@2024!","display_name":"Test Learner","role":"learner"}'
56	        if ($reg2.message -match "learner") { Log-Pass "Second user registered with learner role" }
57	
58	        # RBAC test
59	        $ll = Invoke-RestMethod -Method Post -Uri "http://localhost:${API_PORT}/api/auth/login" -ContentType "application/json" -Body '{"username":"testlearner","password":"Learner@2024!"}'
60	        $lh = @{ "Authorization" = "Bearer $($ll.token)" }
61	        try { Invoke-RestMethod -Uri "http://localhost:${API_PORT}/api/procurement/settlements" -Headers $lh; Log-Fail "Learner accessed settlements" }
62	        catch { if ($_.Exception.Response.StatusCode.value__ -eq 404) { Log-Pass "RBAC: Learner gets 404 (feature invisible)" } else { Log-Fail "RBAC: Got $($_.Exception.Response.StatusCode.value__)" } }
63	    }
64	} catch { Log-Fail "Login/API test failed: $_" }
65	
66	Log-Info "Phase 4: Integration tests..."
67	$net = (docker network ls --format '{{.Name}}' | Select-String 'repo' | Select-Object -First 1).ToString().Trim()
68	docker run --rm --network=$net -e "TEST_DATABASE_URL=postgres://wlpr:wlpr_secret@db:5432/wlpr_portal?sslmode=disable" -v "${scriptDir}:/src:ro" golang:1.22-alpine sh -c "cp -r /src /app && cd /app && go work sync && go test -v -tags=integration -count=1 -timeout=120s ./tests/e2e/backend/... 2>&1"
69	if ($LASTEXITCODE -eq 0) { Log-Pass "Integration tests passed" } else { Log-Fail "Integration tests failed" }
70	
71	Log-Info "Phase 5: Unit tests..."
72	docker run --rm -v "${scriptDir}:/src:ro" golang:1.22-alpine sh -c "cp -r /src /app && cd /app && go work sync && go test -v -count=1 -timeout=120s ./tests/unit/backend/... ./tests/api/backend/... 2>&1"
73	if ($LASTEXITCODE -eq 0) { Log-Pass "Backend unit and API tests passed" } else { Log-Fail "Backend unit and API tests failed" }
74	
75	Log-Info "Phase 6: Frontend tests..."
76	docker run --rm -v "${scriptDir}/frontend:/src:ro" node:20-alpine sh -c "cp -r /src /app && cd /app && npm install --legacy-peer-deps 2>&1 | tail -1 && npx vitest run 2>&1"
77	if ($LASTEXITCODE -eq 0) { Log-Pass "Frontend tests passed" } else { Log-Fail "Frontend tests failed" }
78	
79	Log-Info "Phase 7: Cleanup..."
80	docker compose down -v --remove-orphans
81	
82	if ($failed -eq 0) { Write-Host "`n  ALL TESTS PASSED" -ForegroundColor Green; exit 0 }
83	else { Write-Host "`n  SOME TESTS FAILED" -ForegroundColor Red; exit 1 }
